def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        if capacity < item:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        for j in range(1, 11):
            if j % 2 == 0:
                weight = 1 / (j * 1.5)
            else:
                weight = 1 / j
            score += weight * (ratio ** j)
        if capacity < item * 1.2:
            score *= 1.5
            for k in range(3):
                score += (ratio ** (k+1)) * 0.1
        elif capacity > item * 4:
            score *= 0.7
            for k in range(2,5):
                score -= (ratio ** k) * 0.05
        else:
            for m in range(1,4):
                if (capacity / item) % m == 0:
                    score *= 1 + 0.05 * m
                else:
                    score *= 1 - 0.02 * m
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 15
    return priorities
